    expect(r1.remainingCap).toBe(300);

    const r2 = processClaim(policy, {
      damages: [{ itemType: "amulet", amount: 1000 }],
    });
    // would-be 900, but cap remaining only 300
    expect(r2.payout).toBe(300);
    expect(r2.remainingCap).toBe(0);
  });

